namespace FlawlessChips.Tests;

public class FlawlessTiaTests
{
    [Test]
    public async Task TestStartupStateMatchesSim2600()
    {
        var chip = new FlawlessTia();

        chip.Startup();

        // This state was retrieved from Sim2600 by running the equivalent simulation.
        await Assert.That(chip.GetState()).IsEqualTo(
            "");
    }

    [Test]
    public async Task TestAtari2600Console()
    {
        // Create console, load test ROM, run for a frame, compare state.
        var console = new Atari2600Console(File.ReadAllBytes("Tia/Assets/HelloWorld.bin"));

        await Assert.That(console.Sim6507.GetState()).IsEqualTo(
            "");

        await Assert.That(console.SimTIA.GetState()).IsEqualTo(
            "");

        // It takes exactly 119066 half cycles to produce the first frame (based on Sim2600-CS), 
        // so we'll run that many half cycles and then compare state with Sim2600-CS.
        for (var i = 0; i < 119066; i++)
        {
            console.AdvanceOneHalfClock();
        }

        // This state was retrieved from Sim2600 by running the equivalent simulation.
        await Assert.That(console.SimTIA.GetState()).IsEqualTo(
            "");
    }
}